'use server'

import { CategoryService } from '@/services/category.service'
import { CategoryFormData } from '@/schemas/category.schema'
import { revalidatePath } from 'next/cache'

export async function createCategoryAction(data: CategoryFormData) {
  try {
    const category = await CategoryService.createCategory(data)
    revalidatePath('/admin/categories')
    return { success: true, data: category }
  } catch (error: any) {
    if (error?.code === '23505') {
      return { success: false, error: 'Đường dẫn (slug) đã tồn tại' }
    }
    return { success: false, error: error.message || 'Có lỗi xảy ra khi tạo danh mục' }
  }
}

export async function updateCategoryAction(id: string, data: CategoryFormData) {
  try {
    const category = await CategoryService.updateCategory(id, data)
    revalidatePath('/admin/categories')
    return { success: true, data: category }
  } catch (error: any) {
    if (error?.code === '23505') {
      return { success: false, error: 'Đường dẫn (slug) đã tồn tại' }
    }
    return { success: false, error: error.message || 'Có lỗi xảy ra khi cập nhật danh mục' }
  }
}

export async function deleteCategoryAction(id: string) {
  try {
    await CategoryService.deleteCategory(id)
    revalidatePath('/admin/categories')
    return { success: true }
  } catch (error: any) {
    return { success: false, error: error.message || 'Có lỗi xảy ra khi xóa danh mục' }
  }
}

'use server'

import { ProductService } from '@/services/product.service'
import { ProductFormData } from '@/schemas/product.schema'
import { revalidatePath } from 'next/cache'
import { createClient } from '@/lib/supabase/server'

async function getAdminId() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('Unauthorized')
  return user.id
}

export async function createProductAction(data: ProductFormData) {
  try {
    const adminId = await getAdminId()
    const product = await ProductService.createProduct(data, adminId)
    revalidatePath('/admin/products')
    revalidatePath('/san-pham')
    revalidatePath('/')
    return { success: true, data: product }
  } catch (error: any) {
    if (error?.code === '23505') {
      return { success: false, error: 'Đường dẫn (slug) đã tồn tại' }
    }
    return { success: false, error: error.message || 'Có lỗi xảy ra khi tạo sản phẩm' }
  }
}

export async function updateProductAction(id: string, data: ProductFormData) {
  try {
    const adminId = await getAdminId()
    const product = await ProductService.updateProduct(id, data, adminId)
    revalidatePath('/admin/products')
    revalidatePath(`/san-pham/${data.slug}`)
    revalidatePath('/san-pham')
    revalidatePath('/')
    return { success: true, data: product }
  } catch (error: any) {
    if (error?.code === '23505') {
      return { success: false, error: 'Đường dẫn (slug) đã tồn tại' }
    }
    return { success: false, error: error.message || 'Có lỗi xảy ra khi cập nhật sản phẩm' }
  }
}

export async function deleteProductAction(id: string) {
  try {
    await ProductService.deleteProduct(id)
    revalidatePath('/admin/products')
    revalidatePath('/san-pham')
    revalidatePath('/')
    return { success: true }
  } catch (error: any) {
    return { success: false, error: error.message || 'Có lỗi xảy ra khi xóa sản phẩm' }
  }
}

