import { ProductForm } from '@/features/admin/products/components/ProductForm'
import { CategoryService } from '@/services/category.service'
import { ProductRepository } from '@/repositories/product.repository'
import { notFound } from 'next/navigation'

export const revalidate = 0

export default async function EditProductPage({ params }: { params: Promise<{ id: string }> }) {
  const resolvedParams = await params

  try {
    const product = await ProductRepository.getProductById(resolvedParams.id)
    const { data: categories } = await CategoryService.getPaginatedCategories(1, 100, '')

    return (
      <div className="max-w-4xl mx-auto py-6">
        <ProductForm initialData={product} categories={categories} />
      </div>
    )
  } catch (error) {
    notFound()
  }
}

'use client'

import { useState, useEffect } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { categorySchema, CategoryFormData } from '@/schemas/category.schema'
import { Category } from '@/types/category.type'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog'
import { createCategoryAction, updateCategoryAction } from '@/actions/admin/category.actions'
import { toast } from 'sonner'
import { Checkbox } from '@/components/ui/checkbox'

interface Props {
  open: boolean
  onOpenChange: (open: boolean) => void
  initialData?: Category | null
}

export function CategoryFormDialog({ open, onOpenChange, initialData }: Props) {
  const [loading, setLoading] = useState(false)

  const {
    register,
    handleSubmit,
    setValue,
    reset,
    watch,
    formState: { errors },
  } = useForm<CategoryFormData>({
    resolver: zodResolver(categorySchema),
    defaultValues: {
      name: '',
      slug: '',
      description: '',
      image_url: '',
      is_active: true,
    },
  })

  const isActive = watch('is_active')

  useEffect(() => {
    if (initialData) {
      reset({
        name: initialData.name,
        slug: initialData.slug,
        description: initialData.description,
        image_url: initialData.image_url,
        is_active: initialData.is_active,
      })
    } else {
      reset({
        name: '',
        slug: '',
        description: '',
        image_url: '',
        is_active: true,
      })
    }
  }, [initialData, reset, open])

  // Auto-generate slug from name if not editing
  const name = watch('name')
  useEffect(() => {
    if (!initialData && name) {
      const generatedSlug = name
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/đ/g, 'd')
        .replace(/[^a-z0-9\s-]/g, '')
        .trim()
        .replace(/\s+/g, '-')
      setValue('slug', generatedSlug)
    }
  }, [name, initialData, setValue])

  const onSubmit = async (data: CategoryFormData) => {
    setLoading(true)
    let result
    if (initialData) {
      result = await updateCategoryAction(initialData.id, data)
    } else {
      result = await createCategoryAction(data)
    }

    setLoading(false)

    if (result.success) {
      toast.success(initialData ? 'Cập nhật danh mục thành công' : 'Thêm danh mục thành công')
      onOpenChange(false)
    } else {
      toast.error(result.error)
    }
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <form onSubmit={handleSubmit(onSubmit)}>
          <DialogHeader>
            <DialogTitle>{initialData ? 'Sửa Danh Mục' : 'Thêm Danh Mục'}</DialogTitle>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="name">Tên danh mục <span className="text-red-500">*</span></Label>
              <Input id="name" {...register('name')} />
              {errors.name && <span className="text-sm text-red-500">{errors.name.message}</span>}
            </div>

            <div className="grid gap-2">
              <Label htmlFor="slug">Đường dẫn (Slug) <span className="text-red-500">*</span></Label>
              <Input id="slug" {...register('slug')} />
              {errors.slug && <span className="text-sm text-red-500">{errors.slug.message}</span>}
            </div>

            <div className="grid gap-2">
              <Label htmlFor="description">Mô tả</Label>
              <Input id="description" {...register('description')} />
            </div>

            <div className="grid gap-2">
              <Label htmlFor="image_url">Link ảnh</Label>
              <Input id="image_url" {...register('image_url')} />
              {errors.image_url && <span className="text-sm text-red-500">{errors.image_url.message}</span>}
            </div>

            <div className="flex items-center space-x-2 mt-2">
              <Checkbox 
                id="is_active" 
                checked={isActive} 
                onCheckedChange={(checked) => setValue('is_active', checked === true)} 
              />
              <Label htmlFor="is_active" className="cursor-pointer">Hiển thị danh mục này</Label>
            </div>
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
              Hủy
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? 'Đang lưu...' : 'Lưu lại'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

'use client'

import { useState } from 'react'
import { Category } from '@/types/category.type'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Pencil, Trash2, Plus, Search } from 'lucide-react'
import { CategoryFormDialog } from './CategoryFormDialog'
import { deleteCategoryAction } from '@/actions/admin/category.actions'
import { toast } from 'sonner'
import { Input } from '@/components/ui/input'
import { useRouter } from 'next/navigation'

interface Props {
  initialCategories: Category[]
  totalCount: number
  currentPage: number
  searchTerm: string
}

export function CategoryList({ initialCategories, totalCount, currentPage, searchTerm }: Props) {
  const router = useRouter()
  const [categories, setCategories] = useState(initialCategories)
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [editingCategory, setEditingCategory] = useState<Category | null>(null)
  const [searchInput, setSearchInput] = useState(searchTerm)
  const [isDeleting, setIsDeleting] = useState<string | null>(null)

  const handleEdit = (category: Category) => {
    setEditingCategory(category)
    setIsDialogOpen(true)
  }

  const handleCreate = () => {
    setEditingCategory(null)
    setIsDialogOpen(true)
  }

  const handleDelete = async (id: string) => {
    if (!confirm('Bạn có chắc chắn muốn xóa danh mục này?')) return

    setIsDeleting(id)
    const result = await deleteCategoryAction(id)
    setIsDeleting(null)

    if (result.success) {
      toast.success('Xóa danh mục thành công')
      // Note: revalidatePath will refresh the page from server, but we can also optimistically remove it.
      setCategories(categories.filter(c => c.id !== id))
    } else {
      toast.error(result.error)
    }
  }

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault()
    router.push(`/admin/categories?search=${encodeURIComponent(searchInput)}`)
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <form onSubmit={handleSearch} className="flex gap-2 max-w-sm w-full">
          <Input 
            placeholder="Tìm kiếm danh mục..." 
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
          />
          <Button type="submit" variant="secondary">
            <Search className="h-4 w-4" />
          </Button>
        </form>
        <Button onClick={handleCreate} className="bg-blue-600 hover:bg-blue-700">
          <Plus className="h-4 w-4 mr-2" />
          Thêm danh mục
        </Button>
      </div>

      <div className="border rounded-md bg-white">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Hình ảnh</TableHead>
              <TableHead>Tên danh mục</TableHead>
              <TableHead>Đường dẫn (Slug)</TableHead>
              <TableHead>Trạng thái</TableHead>
              <TableHead className="text-right">Thao tác</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {categories.length === 0 ? (
              <TableRow>
                <TableCell colSpan={5} className="text-center h-24 text-slate-500">
                  Không tìm thấy danh mục nào.
                </TableCell>
              </TableRow>
            ) : (
              categories.map((category) => (
                <TableRow key={category.id}>
                  <TableCell>
                    {category.image_url ? (
                      <img src={category.image_url} alt={category.name} className="w-10 h-10 object-contain rounded border bg-slate-50" />
                    ) : (
                      <div className="w-10 h-10 rounded border bg-slate-100 flex items-center justify-center text-xs text-slate-400">Trống</div>
                    )}
                  </TableCell>
                  <TableCell className="font-medium">{category.name}</TableCell>
                  <TableCell className="text-slate-500">{category.slug}</TableCell>
                  <TableCell>
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${category.is_active ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700'}`}>
                      {category.is_active ? 'Hiển thị' : 'Đang ẩn'}
                    </span>
                  </TableCell>
                  <TableCell className="text-right space-x-2">
                    <Button variant="outline" size="icon" onClick={() => handleEdit(category)}>
                      <Pencil className="h-4 w-4 text-blue-600" />
                    </Button>
                    <Button 
                      variant="outline" 
                      size="icon" 
                      onClick={() => handleDelete(category.id)}
                      disabled={isDeleting === category.id}
                    >
                      <Trash2 className="h-4 w-4 text-red-600" />
                    </Button>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Basic Pagination - can be extracted to a separate component later */}
      {totalCount > 10 && (
        <div className="flex justify-end gap-2">
          <Button 
            variant="outline" 
            disabled={currentPage <= 1}
            onClick={() => router.push(`/admin/categories?page=${currentPage - 1}${searchTerm ? `&search=${searchTerm}` : ''}`)}
          >
            Trước
          </Button>
          <Button 
            variant="outline" 
            disabled={currentPage * 10 >= totalCount}
            onClick={() => router.push(`/admin/categories?page=${currentPage + 1}${searchTerm ? `&search=${searchTerm}` : ''}`)}
          >
            Sau
          </Button>
        </div>
      )}

      {isDialogOpen && (
        <CategoryFormDialog
          open={isDialogOpen}
          onOpenChange={setIsDialogOpen}
          initialData={editingCategory}
        />
      )}
    </div>
  )
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({
    request,
  })

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
          supabaseResponse = NextResponse.next({
            request,
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        },
      },
    }
  )

  const {
    data: { user },
  } = await supabase.auth.getUser()

  const url = request.nextUrl.clone()
  const pathname = url.pathname

  // Check roles if user is authenticated and trying to access admin
  if (pathname.startsWith('/admin')) {
    if (!user) {
      url.pathname = '/login'
      return NextResponse.redirect(url)
    }

    const { data: profile } = await supabase
      .from('profiles')
      .select('role')
      .eq('id', user.id)
      .single()

    if (profile?.role !== 'admin') {
      url.pathname = '/'
      return NextResponse.redirect(url)
    }
  }

  // Protected user routes
  const protectedRoutes = ['/tai-khoan', '/don-hang', '/nap-tien', '/thanh-toan']
  const isProtectedRoute = protectedRoutes.some((route) => pathname.startsWith(route))

  if (isProtectedRoute && !user) {
    url.pathname = '/login'
    return NextResponse.redirect(url)
  }

  // Redirect away from auth pages if logged in
  if ((pathname === '/login' || pathname === '/register') && user) {
    url.pathname = '/'
    return NextResponse.redirect(url)
  }

  return supabaseResponse
}

import { createServerClient, type CookieOptions } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            )
          } catch {
            // The `setAll` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  )
}
